import chesse from "../images/chesse.png";
import egg from "../images/egg.png";
import ramensari from "../images/ramensari.jpg";

export const options = [
  {
    option_id: 1,
    option_name: "치즈 추가",
    option_price: 1000,
    option_image: chesse,
    option_is_available: true,
  },
  {
    option_id: 2,
    option_name: "계란 추가",
    option_price: 1000,
    option_image: egg,
    option_is_available: true,
  },
  {
    option_id: 3,
    option_name: "라면사리 추가",
    option_price: 1000,
    option_image: ramensari,
    option_is_available: true,
  },
];
